DROP TABLE IF EXISTS `bookings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bookings` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `booking_code` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` int unsigned DEFAULT NULL,
  `tour_id` int unsigned DEFAULT NULL,
  `tour_title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tour_link` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `tour_image` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `departure_label` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `duration_label` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `customer_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `customer_email` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `customer_phone` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `customer_note` text COLLATE utf8mb4_unicode_ci,
  `adult_quantity` int NOT NULL DEFAULT '1',
  `child_quantity` int NOT NULL DEFAULT '0',
  `infant_quantity` int NOT NULL DEFAULT '0',
  `adult_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `child_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `infant_price` decimal(12,2) NOT NULL DEFAULT '0.00',
