INSERT INTO `tour_itinerary_day_translations` VALUES (21,11,'vi','TPHCM - BOSTON','Quý khách tập trung ở sân bay Tân Sơn Nhất, làm thủ tục đáp chuyến bay đi Boston.<p>Quá cảnh tại sân bay <strong>Đào Viên</strong> và <strong>Seattle</strong>.</p><p><p>Nghỉ đêm trên máy bay.</p></p><p><br></p>'),(22,11,'en','HCMC - BOSTON','Quý khách tập trung ở sân bay Tân Sơn Nhất, làm thủ tục đáp chuyến bay đi Boston.<p>Quá cảnh tại sân bay <strong>Đào Viên</strong> và <strong>Seattle</strong>.</p><p><p>Nghỉ đêm trên máy bay.</p></p><p><br></p>'),(23,12,'vi','BOSTON CITY TOUR','Đến sân bay quốc tế <strong>Logan</strong>, quý khách làm thủ tục nhập cảnh Mỹ, nhận hành lý.<p><br></p><p>Xe đưa Quý khách đi\r\ntham quan Thành phố Boston, tham quan các địa danh nổi tiếng sau:</p><p><ul><li><strong>Công viên Thành phố Boston</strong> - là công viên lâu đời nhất của Mỹ. Công viên là một mảng xanh rộng lớn bao gồm các cây lớn, được người dân địa phương và các du khách rất yêu thích.</li><li><strong>&nbsp;Học viện Công nghệ Massachusetts</strong> (Massachusetts Institute of TechnBosology): Đây là trường đại học và viện nghiên cứu về khoa học và công nghệ hàng đầu ở Mỹ và trên thế giới.</li></ul><p>Ăn trưa và sau đó về khách sạn nhận phòng.</p><p><br></p><p>Buổi chiều, quý khách tham quan<strong> Bảo tàng Khoa học Boston</strong> (chụp hình bên ngoài). Đây là một sở thú trong nhà ở Boston, Massachusetts, nằm trong Công viên Khoa học, Bảo tàng này trưng bày rất nhiều mẫu vật bắt mắt, nhằm mở rộng các kiến thức về khoa học, vũ trụ, động vật cho các du khách tham quan.</p><p>Ăn tối và sau đó về khách sạn nghỉ ngơi.</p><p>Tự do khám phá thành phố về đêm.</p></p><p><p><strong><em>Nghỉ đêm tại Boston.</em></strong><strong></strong></p></p>'),(24,12,'en','BOSTON CITY TOUR','Đến sân bay quốc tế <strong>Logan</strong>, quý khách làm thủ tục nhập cảnh Mỹ, nhận hành lý.<p><br></p><p>Xe đưa Quý khách đi\r\ntham quan Thành phố Boston, tham quan các địa danh nổi tiếng sau:</p><p><ul><li><strong>Công viên Thành phố Boston</strong> - là công viên lâu đời nhất của Mỹ. Công viên là một mảng xanh rộng lớn bao gồm các cây lớn, được người dân địa phương và các du khách rất yêu thích.</li><li><strong>&nbsp;Học viện Công nghệ Massachusetts</strong> (Massachusetts Institute of TechnBosology): Đây là trường đại học và viện nghiên cứu về khoa học và công nghệ hàng đầu ở Mỹ và trên thế giới.</li></ul><p>Ăn trưa và sau đó về khách sạn nhận phòng.</p><p><br></p><p>Buổi chiều, quý khách tham quan<strong> Bảo tàng Khoa học Boston</strong> (chụp hình bên ngoài). Đây là một sở thú trong nhà ở Boston, Massachusetts, nằm trong Công viên Khoa học, Bảo tàng này trưng bày rất nhiều mẫu vật bắt mắt, nhằm mở rộng các kiến thức về khoa học, vũ trụ, động vật cho các du khách tham quan.</p><p>Ăn tối và sau đó về khách sạn nghỉ ngơi.</p><p>Tự do khám phá thành phố về đêm.</p></p><p><p><strong><em>Nghỉ đêm tại Boston.</em></strong><strong></strong></p></p>'),(25,13,'vi','THAM QUAN, KHÁM PHÁ NEW YORK','<p>Ăn sáng tại khách sạn.</p><p>&nbsp;</p><p>Quý khách khởi hành tham quan thành phố New York với&nbsp;Phố Wall&nbsp;- trung tâm của khu tài chính New York và là nơi trao đổi cổ phiếu lớn nhất thế giới,&nbsp;NYSE&nbsp;(thị trường chứng khoán New York)&nbsp;- một biểu tượng thương mại nổi tiếng cùng&nbsp;Charging Bull (Wall Street Bull),&nbsp;Ground Zero&nbsp;– nơi ghi dấu của tòa tháp đôi Thương mại WTC nổi tiếng trước đây, đến&nbsp;Vịnh Hudson&nbsp;tham quan&nbsp;tượng Nữ thần Tự do&nbsp;nổi tiếng.</p><p>&nbsp;</p><p><br></p><p>Sau bữa trưa, quý khách tiếp tục tham quan:&nbsp;Trụ sở Liên Hiệp Quốc, Các tòa nhà chính, Ban Thư ký - một trong những tòa nhà chọc trời đầu tiên của thành phố.&nbsp;Trung tâm Rockefeller, mốc lịch sử quốc gia ở trung tâm của Midtown Manhattan,&nbsp;Nhà thờ Saint Patrick&nbsp;– nơi ở của của Tổng Giáo Phận Roman Catholic của New York,&nbsp;Times Square&nbsp;– quảng trường nhộn nhịp nhất của New York với nhiều Nhà hát Broadway, rạp chiếu phim và các bảng quảng cáo điện tử đầy màu sắc,&nbsp;Fifth Avenue&nbsp;– một trong những con phố mua sắm nổi tiếng nhất thế giới; tham quan, mua sắm ở khu&nbsp;China Town.</p><p>&nbsp;</p><p><br></p><p>Đoàn ăn tối ở nhà hàng địa phương và về khách sạn nghỉ ngơi.&nbsp;</p><p>&nbsp;</p><p><em>Nghỉ</em>&nbsp;<em>đêm</em>&nbsp;<em>tại New York</em><em>.</em></p>'),(26,13,'en','THAM QUAN, KHÁM PHÁ NEW YORK','<p>Ăn sáng tại khách sạn.</p><p>&nbsp;</p><p>Quý khách khởi hành tham quan thành phố New York với&nbsp;Phố Wall&nbsp;- trung tâm của khu tài chính New York và là nơi trao đổi cổ phiếu lớn nhất thế giới,&nbsp;NYSE&nbsp;(thị trường chứng khoán New York)&nbsp;- một biểu tượng thương mại nổi tiếng cùng&nbsp;Charging Bull (Wall Street Bull),&nbsp;Ground Zero&nbsp;– nơi ghi dấu của tòa tháp đôi Thương mại WTC nổi tiếng trước đây, đến&nbsp;Vịnh Hudson&nbsp;tham quan&nbsp;tượng Nữ thần Tự do&nbsp;nổi tiếng.</p><p>&nbsp;</p><p><br></p><p>Sau bữa trưa, quý khách tiếp tục tham quan:&nbsp;Trụ sở Liên Hiệp Quốc, Các tòa nhà chính, Ban Thư ký - một trong những tòa nhà chọc trời đầu tiên của thành phố.&nbsp;Trung tâm Rockefeller, mốc lịch sử quốc gia ở trung tâm của Midtown Manhattan,&nbsp;Nhà thờ Saint Patrick&nbsp;– nơi ở của của Tổng Giáo Phận Roman Catholic của New York,&nbsp;Times Square&nbsp;– quảng trường nhộn nhịp nhất của New York với nhiều Nhà hát Broadway, rạp chiếu phim và các bảng quảng cáo điện tử đầy màu sắc,&nbsp;Fifth Avenue&nbsp;– một trong những con phố mua sắm nổi tiếng nhất thế giới; tham quan, mua sắm ở khu&nbsp;China Town.</p><p>&nbsp;</p><p><br></p><p>Đoàn ăn tối ở nhà hàng địa phương và về khách sạn nghỉ ngơi.&nbsp;</p><p>&nbsp;</p><p><em>Nghỉ</em>&nbsp;<em>đêm</em>&nbsp;<em>tại New York</em><em>.</em></p>'),(27,14,'vi','NEW YORK - PHILADELPHIA - WASHINGTON D.C','<p>Ăn sáng tại khách sạn và làm thủ tục trả phòng.</p><p>&nbsp;</p><p>Đoàn khởi hành đến&nbsp;Washington D.C. Trên đường di chuyển, quý khách sẽ đến thăm&nbsp;Thành phố Philadelphia, chụp hình bên ngoài&nbsp;Tòa nhà Độc Lập (Independence Hall)&nbsp;là nơi đầu tiên mà các bản Tuyên ngôn Độc lập đã được phê duyệt,&nbsp;Quả chuông Tự Do (Liberty Bell)&nbsp;- biểu tượng của nền độc lập và là nơi mà tiếng chuông đầu tiên của tự do được ngân lên.</p><p>&nbsp;</p><p><br></p><p>Đến Washington DC, quý khách đến thăm&nbsp;Đài tưởng niệm Abraham Lincoln&nbsp;- Tổng thống thứ 16 của Hoa Kỳ, sau đó tham quan&nbsp;khu Eden&nbsp;để tìm hiểu cuộc sống thực sự của cộng đồng Việt Nam tại Hoa Kỳ.</p><p>&nbsp;</p><p>Ăn tối tại nhà hàng địa phương.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Washington D.C.</em></p>'),(28,14,'en','NEW YORK - PHILADELPHIA - WASHINGTON D.C','<p>Ăn sáng tại khách sạn và làm thủ tục trả phòng.</p><p>&nbsp;</p><p>Đoàn khởi hành đến&nbsp;Washington D.C. Trên đường di chuyển, quý khách sẽ đến thăm&nbsp;Thành phố Philadelphia, chụp hình bên ngoài&nbsp;Tòa nhà Độc Lập (Independence Hall)&nbsp;là nơi đầu tiên mà các bản Tuyên ngôn Độc lập đã được phê duyệt,&nbsp;Quả chuông Tự Do (Liberty Bell)&nbsp;- biểu tượng của nền độc lập và là nơi mà tiếng chuông đầu tiên của tự do được ngân lên.</p><p>&nbsp;</p><p><br></p><p>Đến Washington DC, quý khách đến thăm&nbsp;Đài tưởng niệm Abraham Lincoln&nbsp;- Tổng thống thứ 16 của Hoa Kỳ, sau đó tham quan&nbsp;khu Eden&nbsp;để tìm hiểu cuộc sống thực sự của cộng đồng Việt Nam tại Hoa Kỳ.</p><p>&nbsp;</p><p>Ăn tối tại nhà hàng địa phương.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Washington D.C.</em></p>'),(29,15,'vi','WASHINGTON D.C','<p>Ăn sáng. Tham quan chụp hình bên ngoài&nbsp;Nhà&nbsp;Trắng&nbsp;- nơi làm việc của tổng thống; chụp hình bên ngoài&nbsp;Điện&nbsp;Capitol&nbsp;và&nbsp;Bảo tàng&nbsp;Lịch sử Tự nhiên&nbsp;Quốc gia&nbsp;- nơi duy trì bộ sưu tập lớn nhất và quan trọng nhất của thế giới hiện vật hàng không và không gian;</p><p>Tham quan&nbsp;Hồ Tidal Basin&nbsp;– nằm trong khuôn viên vườn quốc gia Washington D.C, Hồ nổi bật với vẻ đẹp thanh bình và nên thơ.</p><p>&nbsp;</p><p>Lầu Năm Góc&nbsp;- trụ sở của Bộ Quốc phòng và các cơ quan quân sự cao nhất của Mỹ.</p><p>&nbsp;</p><p><br></p><p>Ăn trưa tại nhà hàng địa phương. Sau đó du khách sẽ có thời gian mua sắm tại&nbsp;Trung tâm mua sắm nổi tiếng Pentagon.&nbsp;</p><p>&nbsp;</p><p><em>Nghỉ đêm tại</em>&nbsp;<em>Washington</em><em>&nbsp;D.C.</em></p><p>&nbsp;</p>'),(30,15,'en','WASHINGTON D.C','<p>Ăn sáng. Tham quan chụp hình bên ngoài&nbsp;Nhà&nbsp;Trắng&nbsp;- nơi làm việc của tổng thống; chụp hình bên ngoài&nbsp;Điện&nbsp;Capitol&nbsp;và&nbsp;Bảo tàng&nbsp;Lịch sử Tự nhiên&nbsp;Quốc gia&nbsp;- nơi duy trì bộ sưu tập lớn nhất và quan trọng nhất của thế giới hiện vật hàng không và không gian;</p><p>Tham quan&nbsp;Hồ Tidal Basin&nbsp;– nằm trong khuôn viên vườn quốc gia Washington D.C, Hồ nổi bật với vẻ đẹp thanh bình và nên thơ.</p><p>&nbsp;</p><p>Lầu Năm Góc&nbsp;- trụ sở của Bộ Quốc phòng và các cơ quan quân sự cao nhất của Mỹ.</p><p>&nbsp;</p><p><br></p><p>Ăn trưa tại nhà hàng địa phương. Sau đó du khách sẽ có thời gian mua sắm tại&nbsp;Trung tâm mua sắm nổi tiếng Pentagon.&nbsp;</p><p>&nbsp;</p><p><em>Nghỉ đêm tại</em>&nbsp;<em>Washington</em><em>&nbsp;D.C.</em></p><p>&nbsp;</p>'),(31,16,'vi','WASHINGTON D.C – GRAND CANYON - HOOVER DAM - LAS VEGAS','<p>Sau khi ăn sáng, quý khách trả phòng và đáp chuyến bay đi Las Vegas. Xe đưa đoàn đi tham quan&nbsp;Grand Canyon&nbsp;-&nbsp;một trong 7 kỳ quan thiên nhiên của thế giới&nbsp;với những vực sâu, những phiến đá được xếp thành nhiều tầng. Đến đây, Quý khách sẽ choáng ngợp khi nhìn thấy những tảng đá vôi to lớn với vô số đỉnh nhọn với nhiều hình thù kỳ lạ, những vực hẻm trải dài từ Marble George đến Grand Waschiffs hơn 300km với độ sâu thăm thẳm…</p><p>&nbsp;</p><p>Quý khách sẽ tham quan&nbsp;West Rim, đi&nbsp;Skywalk&nbsp;- chiếc cầu bằng kính trong suốt có hình móng ngựa&nbsp;ngắm nhìn toàn cảnh&nbsp;Grand Canyon&nbsp;và&nbsp;Sông Colorado&nbsp;xanh thẳm.</p><p>&nbsp;</p><p>Ngoài ra, tại đây Quý khách còn có thể đi trực thăng tham quan Grand Canyon từ trên cao&nbsp;<em>(Quý khách tự túc chi phí mua vé vọng cảnh Skywalk và phí đi trực thăng)</em><em>.</em></p><p>&nbsp;</p><p>Sau đó, khởi hành đi tham quan&nbsp;Đập thủy điện Hoover&nbsp;lớn nhất nước Mỹ và&nbsp;hồ nước nhân tạo Mead.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Las Vegas</em><em>.</em></p>'),(32,16,'en','WASHINGTON D.C – GRAND CANYON - HOOVER DAM - LAS VEGAS','<p>Sau khi ăn sáng, quý khách trả phòng và đáp chuyến bay đi Las Vegas. Xe đưa đoàn đi tham quan&nbsp;Grand Canyon&nbsp;-&nbsp;một trong 7 kỳ quan thiên nhiên của thế giới&nbsp;với những vực sâu, những phiến đá được xếp thành nhiều tầng. Đến đây, Quý khách sẽ choáng ngợp khi nhìn thấy những tảng đá vôi to lớn với vô số đỉnh nhọn với nhiều hình thù kỳ lạ, những vực hẻm trải dài từ Marble George đến Grand Waschiffs hơn 300km với độ sâu thăm thẳm…</p><p>&nbsp;</p><p>Quý khách sẽ tham quan&nbsp;West Rim, đi&nbsp;Skywalk&nbsp;- chiếc cầu bằng kính trong suốt có hình móng ngựa&nbsp;ngắm nhìn toàn cảnh&nbsp;Grand Canyon&nbsp;và&nbsp;Sông Colorado&nbsp;xanh thẳm.</p><p>&nbsp;</p><p>Ngoài ra, tại đây Quý khách còn có thể đi trực thăng tham quan Grand Canyon từ trên cao&nbsp;<em>(Quý khách tự túc chi phí mua vé vọng cảnh Skywalk và phí đi trực thăng)</em><em>.</em></p><p>&nbsp;</p><p>Sau đó, khởi hành đi tham quan&nbsp;Đập thủy điện Hoover&nbsp;lớn nhất nước Mỹ và&nbsp;hồ nước nhân tạo Mead.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Las Vegas</em><em>.</em></p>'),(33,17,'vi','LAS VEGAS - LOS ANGELES','<p>Ăn sáng và trả phòng. Xe đưa đoàn tham quan:</p><p>&nbsp;</p><ul><li>Mua sắm hàng hiệu giảm giá tại các&nbsp;Outlet Mall&nbsp;– thiên đường thật sự của các tín đồ shopping với tất cả các nhãn hàng hiệu nổi tiếng trên thế giới có giá thấp bất ngờ.</li></ul><p>&nbsp;</p><ul><li>Xe đưa quý khách chạy dọc theo trục đường nhộn nhịp, tràn ngập ánh sáng của Las Vegas để ngắm nhìn “The Strip” - con đường dài hơn 6km tập trung những khách sạn và casino tiếng tăm và sang trọng bậc nhất.</li></ul><p>&nbsp;</p><p>Sau đó di chuyển đến Los Angeles. Quý khách ghé thăm&nbsp;Little&nbsp;Saigon&nbsp;- khu vực sinh sống của cộng đồng người Việt và&nbsp;Trung tâm&nbsp;Thọ&nbsp;Lộc&nbsp;Phước&nbsp;- trung tâm mua sắm nổi tiếng của người Việt.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Los Angeles.</em></p>'),(34,17,'en','LAS VEGAS - LOS ANGELES','<p>Ăn sáng và trả phòng. Xe đưa đoàn tham quan:</p><p>&nbsp;</p><ul><li>Mua sắm hàng hiệu giảm giá tại các&nbsp;Outlet Mall&nbsp;– thiên đường thật sự của các tín đồ shopping với tất cả các nhãn hàng hiệu nổi tiếng trên thế giới có giá thấp bất ngờ.</li></ul><p>&nbsp;</p><ul><li>Xe đưa quý khách chạy dọc theo trục đường nhộn nhịp, tràn ngập ánh sáng của Las Vegas để ngắm nhìn “The Strip” - con đường dài hơn 6km tập trung những khách sạn và casino tiếng tăm và sang trọng bậc nhất.</li></ul><p>&nbsp;</p><p>Sau đó di chuyển đến Los Angeles. Quý khách ghé thăm&nbsp;Little&nbsp;Saigon&nbsp;- khu vực sinh sống của cộng đồng người Việt và&nbsp;Trung tâm&nbsp;Thọ&nbsp;Lộc&nbsp;Phước&nbsp;- trung tâm mua sắm nổi tiếng của người Việt.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Los Angeles.</em></p>'),(35,18,'vi','LOS ANGELES','<p>Ăn sáng tại khách sạn. Quý khách bắt đầu hành trình trong ngày:</p><p>&nbsp;</p><p>+ Tham quan trung tâm kinh đô điện ảnh&nbsp;Hollywood, Quý khách tản bộ trên&nbsp;đại lộ Hollywood, dừng chân tại nhà hát&nbsp;Mann’s Chinese Theatre&nbsp;với sân trước của nhà hát in kín dấu giày và dấu bàn tay của hầu hết các nghệ sĩ điện ảnh tiếng tăm.</p><p>&nbsp;</p><p>+ Quý khách tiếp tục tham quan&nbsp;Dolby Theatre&nbsp;- nơi diễn ra lễ trao giải Oscar hàng năm.</p><p><br></p><p>Quý khách lựa chọn tham quan 1 trong 2:&nbsp;công viên Universal Studios (Chi phí tự túc)&nbsp;trường quay của các bộ phim nổi tiếng trong lịch sử điện ảnh thế giới như Kingkong, Hàm cá mập, Công viên khủng long v.v. Quý khách sẽ được tận mắt chứng kiến các kỹ xảo âm thanh khói lửa và nước trong các cảnh&nbsp; động đất, cháy nhà, nổ xe, mưa và nước lũ.</p><p>&nbsp;</p><p>Ăn trưa.</p><p>&nbsp;</p><p>+&nbsp;Xem phim không gian 4 chiều, thử cảm giác hồi hộp trong hầm mộ của bộ phim Mummy Return,&nbsp;Chụp hình cùng các nhân vật&nbsp;của các bộ phim nổi tiếng như Người nhện, Người dơi, Thuyền trưởng Jack Sparrow v.v… Phim 4D Transformer, Quý khách như được hành động cùng các nhân vật trong phim, chắc chắn sẽ để lại Quý khách những ấn tượng khó quên về các kỹ xảo làm phim của điện ảnh Hollywood.</p><p>&nbsp;</p><p>+ Tham quan&nbsp;công viên Disneyland (chi phí tự túc)&nbsp;để đắm mình trong những câu chuyện của những bộ phim Disney, tham quan Fantasyland, New Orleans Square, Adventure Land,..</p><p>&nbsp;</p><p>Quý khách ăn tối tại nhà hàng địa phương và trở về khách sạn nghỉ ngơi.</p><p>&nbsp;</p><p>Ăn tối về khách sạn nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Los Angeles.</em></p>'),(36,18,'en','LOS ANGELES','<p>Ăn sáng tại khách sạn. Quý khách bắt đầu hành trình trong ngày:</p><p>&nbsp;</p><p>+ Tham quan trung tâm kinh đô điện ảnh&nbsp;Hollywood, Quý khách tản bộ trên&nbsp;đại lộ Hollywood, dừng chân tại nhà hát&nbsp;Mann’s Chinese Theatre&nbsp;với sân trước của nhà hát in kín dấu giày và dấu bàn tay của hầu hết các nghệ sĩ điện ảnh tiếng tăm.</p><p>&nbsp;</p><p>+ Quý khách tiếp tục tham quan&nbsp;Dolby Theatre&nbsp;- nơi diễn ra lễ trao giải Oscar hàng năm.</p><p><br></p><p>Quý khách lựa chọn tham quan 1 trong 2:&nbsp;công viên Universal Studios (Chi phí tự túc)&nbsp;trường quay của các bộ phim nổi tiếng trong lịch sử điện ảnh thế giới như Kingkong, Hàm cá mập, Công viên khủng long v.v. Quý khách sẽ được tận mắt chứng kiến các kỹ xảo âm thanh khói lửa và nước trong các cảnh&nbsp; động đất, cháy nhà, nổ xe, mưa và nước lũ.</p><p>&nbsp;</p><p>Ăn trưa.</p><p>&nbsp;</p><p>+&nbsp;Xem phim không gian 4 chiều, thử cảm giác hồi hộp trong hầm mộ của bộ phim Mummy Return,&nbsp;Chụp hình cùng các nhân vật&nbsp;của các bộ phim nổi tiếng như Người nhện, Người dơi, Thuyền trưởng Jack Sparrow v.v… Phim 4D Transformer, Quý khách như được hành động cùng các nhân vật trong phim, chắc chắn sẽ để lại Quý khách những ấn tượng khó quên về các kỹ xảo làm phim của điện ảnh Hollywood.</p><p>&nbsp;</p><p>+ Tham quan&nbsp;công viên Disneyland (chi phí tự túc)&nbsp;để đắm mình trong những câu chuyện của những bộ phim Disney, tham quan Fantasyland, New Orleans Square, Adventure Land,..</p><p>&nbsp;</p><p>Quý khách ăn tối tại nhà hàng địa phương và trở về khách sạn nghỉ ngơi.</p><p>&nbsp;</p><p>Ăn tối về khách sạn nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại Los Angeles.</em></p>'),(37,19,'vi','LOS ANGELES – SAN JOSE','<p>Ăn sáng và làm thủ tục trả phòng. Xe đưa quý khách di chuyển đến&nbsp;San Jose&nbsp;Quý khách sẽ được ngắm nhìn những thung lũng phì nhiêu vùng Trung Bộ Cali, những cánh đồng trồng bông, đào, trái cây trải dài mênh mông bất tận.</p><p>&nbsp;</p><p>Quý khách dừng chân tham quan tại&nbsp;Làng&nbsp;Solvang&nbsp;- là một thị trấn luôn tràn đầy nắng ấm, như tên gọi của nó trong tiếng Ðan Mạch: \"Cánh đồng đầy nắng” (Sunny Field). Mọi thứ ở đây, từ kiến trúc, văn hóa, nghệ thuật, và cả cách sống của người dân đều đẫm “chất” Đan</p><p>Mạch...</p><p>&nbsp;</p><p>Ăn trưa tại Solvang.</p><p>&nbsp;</p><p>Sau bữa trưa, Quý khách tiếp tục hành trình. Đến&nbsp;San Jose, Quý khách ăn tối và di chuyển về khách sạn nhận phòng, tự do nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại San Jose.</em></p>'),(38,19,'en','LOS ANGELES – SAN JOSE','<p>Ăn sáng và làm thủ tục trả phòng. Xe đưa quý khách di chuyển đến&nbsp;San Jose&nbsp;Quý khách sẽ được ngắm nhìn những thung lũng phì nhiêu vùng Trung Bộ Cali, những cánh đồng trồng bông, đào, trái cây trải dài mênh mông bất tận.</p><p>&nbsp;</p><p>Quý khách dừng chân tham quan tại&nbsp;Làng&nbsp;Solvang&nbsp;- là một thị trấn luôn tràn đầy nắng ấm, như tên gọi của nó trong tiếng Ðan Mạch: \"Cánh đồng đầy nắng” (Sunny Field). Mọi thứ ở đây, từ kiến trúc, văn hóa, nghệ thuật, và cả cách sống của người dân đều đẫm “chất” Đan</p><p>Mạch...</p><p>&nbsp;</p><p>Ăn trưa tại Solvang.</p><p>&nbsp;</p><p>Sau bữa trưa, Quý khách tiếp tục hành trình. Đến&nbsp;San Jose, Quý khách ăn tối và di chuyển về khách sạn nhận phòng, tự do nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại San Jose.</em></p>'),(39,20,'vi','SAN JOSE – SAN FRANCISCO','<p>Ăn sáng và làm thủ tục trả phòng. Quý khách khởi hành di chuyển đến&nbsp;Thành phố San Francisco. Đến nơi, đoàn tham quan:</p><p>&nbsp;</p><ul><li>Chiêm ngưỡng&nbsp;Cầu Cổng Vàng&nbsp;- Biểu tượng nổi tiếng nhất của thành phố.</li></ul><p>&nbsp;</p><ul><li>Cảng Ngư Phủ (Fisherman’s Wharf)&nbsp;nhộn nhịp là một điểm du lịch quan trọng của thành phố San Francisco, thu hút nhiều du khách đến thăm viếng hàng năm. Tại đây Quý khách có thể đi tham quan Pier 39 với rất nhiều chú hải cẩu đang nằm tắm nắng, tản bộ dọc con phố và tự do thưởng thức món cua luộc tươi ngon và món súp clam chowder nổi tiếng (chi phí tự túc).</li></ul><p>&nbsp;</p><p>&nbsp;</p><p>Buổi chiều đoàn tham quan:</p><p>&nbsp;</p><ul><li>Đường Hoa Lombard&nbsp;độc đáo với đủ loại hoa đầy màu sắc được trồng và tạo dáng uốn khúc hình chữ S, được công nhận là con phố hẹp và quanh co nhất thế giới.</li></ul><p>&nbsp;</p><ul><li>Quý khách ngắm nhìn toàn cảnh thành phố từ&nbsp;đỉnh&nbsp;đồi Twin Peak,&nbsp;tham quan&nbsp;Toà Thị Chính,&nbsp;Khu Phố Người Hoa.</li></ul><p>&nbsp;</p><p>&nbsp;</p><p>Quý khách ăn tối và di chuyển về khách sạn nhận phòng, tự do nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại San Francisco.</em></p>'),(40,20,'en','SAN JOSE – SAN FRANCISCO','<p>Ăn sáng và làm thủ tục trả phòng. Quý khách khởi hành di chuyển đến&nbsp;Thành phố San Francisco. Đến nơi, đoàn tham quan:</p><p>&nbsp;</p><ul><li>Chiêm ngưỡng&nbsp;Cầu Cổng Vàng&nbsp;- Biểu tượng nổi tiếng nhất của thành phố.</li></ul><p>&nbsp;</p><ul><li>Cảng Ngư Phủ (Fisherman’s Wharf)&nbsp;nhộn nhịp là một điểm du lịch quan trọng của thành phố San Francisco, thu hút nhiều du khách đến thăm viếng hàng năm. Tại đây Quý khách có thể đi tham quan Pier 39 với rất nhiều chú hải cẩu đang nằm tắm nắng, tản bộ dọc con phố và tự do thưởng thức món cua luộc tươi ngon và món súp clam chowder nổi tiếng (chi phí tự túc).</li></ul><p>&nbsp;</p><p>&nbsp;</p><p>Buổi chiều đoàn tham quan:</p><p>&nbsp;</p><ul><li>Đường Hoa Lombard&nbsp;độc đáo với đủ loại hoa đầy màu sắc được trồng và tạo dáng uốn khúc hình chữ S, được công nhận là con phố hẹp và quanh co nhất thế giới.</li></ul><p>&nbsp;</p><ul><li>Quý khách ngắm nhìn toàn cảnh thành phố từ&nbsp;đỉnh&nbsp;đồi Twin Peak,&nbsp;tham quan&nbsp;Toà Thị Chính,&nbsp;Khu Phố Người Hoa.</li></ul><p>&nbsp;</p><p>&nbsp;</p><p>Quý khách ăn tối và di chuyển về khách sạn nhận phòng, tự do nghỉ ngơi.</p><p>&nbsp;</p><p><em>Nghỉ đêm tại San Francisco.</em></p>'),(41,21,'vi','SAN FRANCISCO – AIRPORT','<p>Ăn sáng và tự do mua sắm.</p><p>&nbsp;</p><p>Sau đó, quý khách làm thủ tục trả phòng.</p><p>&nbsp;</p><p>Ăn trưa, khởi hành ra sân bay đáp chuyến bay trở về nước.</p><p>&nbsp;</p><p>Đến sân bay Tân Sơn Nhất, chia tay quý khách và hẹn gặp lại!</p>'),(42,21,'en','SAN FRANCISCO – AIRPORT','<p>Ăn sáng và tự do mua sắm.</p><p>&nbsp;</p><p>Sau đó, quý khách làm thủ tục trả phòng.</p><p>&nbsp;</p><p>Ăn trưa, khởi hành ra sân bay đáp chuyến bay trở về nước.</p><p>&nbsp;</p><p>Đến sân bay Tân Sơn Nhất, chia tay quý khách và hẹn gặp lại!</p>'),(163,82,'vi','TPHCM – PARIS','Quý khách tập trung tại sân bay Tân Sơn Nhất, làm thủ tục đáp chuyến bay đi Paris. Quá cảnh tùy hãng máy bay.<p><br></p><p>Nghỉ đêm trên máy bay.</p>'),(164,82,'en','HCMC – PARIS','<p>Guests gather at Tan Son Nhat International Airport to complete check-in procedures for the flight to Paris. Transit depends on the airline.</p>\r\n<p>Overnight on board.</p>'),(165,83,'vi','AIRPORT CDG - PARIS','<p>Đến sân bay CDG đoàn làm thủ tục nhập cảnh. Sau đó đoàn bắt đầu khám phá <strong>Paris</strong>. Điểm đến đầu tiên là <strong>Đồi Montmartre</strong> - được mệnh danh là “khu phố nghệ sĩ”.</p><p><br></p><p>Bởi nơi đây đã từng là chốn nghỉ chân của rất nhiều những nghệ sĩ nổi tiếng trên thế giới. Đặc biệt có thể kể tới như Van Gogh, Picasso hay Modigliani,… (Chụp hình bên ngoài). Tham quan <strong>Bảo tàng Louvre</strong> - nơi trưng bày các báu vật hội họa, kiến trúc của nhân loại (chụp hình bên ngoài).&nbsp;</p><p><br></p><p>Qúy khách trải nghiệm du thuyền trên dòng <strong>sông Seine</strong> khám phá vẻ đẹp hai bên bờ sông và những cây cầu cổ, tiêu biểu nhất là cầu Alexandre III. <strong>Tháp Eiffel</strong> - công trình kiến trúc bằng sắt sừng sững bên bờ sông Seine, biểu tượng và là niềm tự hào của nước Pháp (chụp hình bên ngoài).</p><p>Đoàn ăn tối và về khách sạn, Qúy khách tự do chiêm ngưỡng Paris về đêm.</p><p>Nghỉ đêm tại Paris.</p><p><br></p>'),(166,83,'en','AIRPORT CDG - PARIS','<p>Arrive at Charles de Gaulle Airport and complete immigration procedures. Begin exploring Paris.</p>\r\n<p>First stop: Montmartre Hill – known as the “artists’ quarter,” once home to many world-famous artists such as Van Gogh, Picasso, and Modigliani (photo stop outside).</p>\r\n<p>Visit the Louvre Museum – home to priceless treasures of art and architecture (photo stop outside).</p>\r\n<p>Enjoy a Seine River cruise to admire the beauty along both riverbanks and historic bridges, especially Alexandre III Bridge.</p>\r\n<p>Visit the Eiffel Tower – the iconic iron structure standing proudly along the Seine River, a symbol of France (photo stop outside).</p>\r\n<p>Dinner at a local restaurant, then return to the hotel. Free time to explore Paris by night.</p>\r\n<p>Overnight in Paris.</p>'),(167,84,'vi','PARIS - COLMAR','Ăn sáng tại khách sạn và trả phòng. Xe đưa đoàn tham quan <strong>Khải\r\nHoàn Môn (L’Arc de Triomphe)</strong>, dạo bộ trên <strong>Đại Lộ Thiên Đường (Champs Élysées)</strong>.&nbsp;<p>Quý khách đến với <strong>Nhà thờ Đức Bà (Notre Dame de Paris)</strong> tên của đại văn hào Victor Hugo (chụp hình bên ngoài) - công trình kiến trúc Gothic tiêu biểu và nổi tiếng thế giới với tác phẩm văn học cùng.</p><p>Ăn trưa\r\nBuổi chiều đoàn lên xe di chuyển đến <strong>Colmar </strong>- được biết đến như là “Venice thu nhỏ” của Pháp, là một kênh đào xinh đẹp nằm ở Colmar.</p><p>Hai bờ kênh được trang trí bởi những hàng cây xanh mát và những bụi hoa sặc sỡ, tạo nên một cảnh quan hữu tình và bình yên.</p><p>Ăn tối và nghỉ đêm tại Colmar</p>'),(168,84,'en','PARIS - COLMAR','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Visit the Arc de Triomphe and stroll along the Champs-Élysées.<br>\r\nStop at Notre Dame Cathedral – a famous Gothic architectural masterpiece associated with Victor Hugo (photo stop outside).</p>\r\n<p>After lunch, depart for Colmar – known as the “Little Venice” of France. The charming canals are lined with green trees and colorful flowers, creating a peaceful and poetic atmosphere.</p>\r\n<p>Dinner and overnight in Colmar.</p>'),(169,85,'vi','COLMAR – INTERLAKEN – ZURICH (THỤY SĨ)','Ăn sáng tại khách sạn, trả phòng.<p>Xe đón đoàn di chuyển đến <strong>Hồ Brienz</strong> - địa điểm checkin nổi tiếng các năm trở lại đây, sau cảnh quay lãng mạn trong bộ Phim Hạ Cánh Nơi Anh.</p><p>Xe đưa quý khách tiếp tục hành trình đến tham quan Làng Iseltwald. Nằm bên bờ hồ Brienz, <strong>làng Iseltwald</strong> là một điểm đến lý tưởng cho những người muốn tránh xa sự ồn ào của thành phố và tận hưởng cảnh quan đẹp như tranh vẽ. Với vẻ đẹp tự nhiên hoang sơ và không khí trong lành, Iseltwald đang trở thành một trong những điểm đến du lịch phổ biến của Thụy Sĩ.</p><p>Ăn trưa Buổi chiều đoàn di chuyển về <strong>Zurich – thủ đô văn hóa của Thụy Sĩ.</strong> Đoàn tham quan tòa thị chính Zurich (chụp hình bên ngoài).</p><p>Quý khách tự do đi bộ dạo chơi, khám phá khu phố cổ.</p><p>Ăn tối và về khách sạn nhận phòng nghỉ ngơi.</p><p>Nghỉ đêm tại Zurich</p>'),(170,85,'en','COLMAR – INTERLAKEN – ZURICH (SWITZERLAND)','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Travel to Lake Brienz – a popular check-in spot featured in the romantic film <em>Crash Landing on You</em>.</p>\r\n<p>Continue to Iseltwald Village. Located on the shores of Lake Brienz, this peaceful village offers breathtaking natural scenery and fresh air, making it a favorite destination in Switzerland.</p>\r\n<p>After lunch, continue to Zurich – the cultural capital of Switzerland. Visit Zurich Town Hall (photo stop outside) and enjoy free time exploring the Old Town.</p>\r\n<p>Dinner and overnight in Zurich.</p>'),(171,86,'vi','ZURICH – ENGELBERG – MILAN','Ăn sáng tại khách sạn, trả phòng.<p>Khởi hành đến <strong>thị trấn Engelberg</strong>. Tại đây quý khách sẽ được đi cáp treo đến <strong>đỉnh núi Titlis</strong>, chiêm ngưỡng cảnh quan thiên nhiên hùng vĩ với những ngọn núi quanh năm tuyết phủ. \r\n\r\nĂn trưa trên núi Titlis.</p><p>Chiều, đoàn di chuyển đến <strong>Milan </strong>- trung tâm thời trang của nước Ý.</p><p>Quý khách tự do dạo chơi mua sắm tại <strong>Galleria Vittorio Emanuele</strong> - khu phố thương mại và triển lãm cổ rộng lớn.</p><p>Ăn tối và nhận phòng khách sạn.</p><p>Nghỉ đêm tại Milan</p>'),(172,86,'en','ZURICH – ENGELBERG – MILAN','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Depart for Engelberg. Take a cable car to Mount Titlis and admire the spectacular snow-covered mountain scenery year-round.</p>\r\n<p>Lunch on Mount Titlis.</p>\r\n<p>In the afternoon, travel to Milan – the fashion capital of Italy. Free time for shopping at Galleria Vittorio Emanuele II, a historic shopping arcade.</p>\r\n<p>Dinner and overnight in Milan.</p>'),(173,87,'vi','MILAN – FLORENCE','Ăn sáng tại khách sạn, trả phòng.<p>Đoàn tham quan <strong>nhà thờ Duomo</strong>\r\nvà dừng chân chụp hình bên ngoài nhà hát <strong>La Scala</strong>.</p><p>Sau khi ăn trưa, quý khách khởi hành đi <strong>Florence </strong>- cái nôi của kinh đô nghệ thuật, nơi quy tụ các giá trị văn hóa tiêu biểu thời Trung cổ.</p><p>Xe đưa đoàn tham quan <strong>Ponte Vecchio</strong> - cầu cổ nằm bắt qua sông Arno ở Florence, Italy - được xây từ thế kỷ 14.</p><p>Sau đó, Đoàn tham quan mua sắm tại <strong>Chợ đồ da Mercato del Porcellino</strong> - Đây được coi là một trong những khu chợ lâu đời nhất thế giới, bởi nó vốn dĩ là khu vực giao thương chính của Florence ngay từ những ngày đầu tiên.</p><p>Đoàn ăn tối và về khách sạn check in.</p><p>Nghỉ đêm tại Florence</p>'),(174,87,'en','MILAN – FLORENCE','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Visit Milan Cathedral (Duomo) and take photos outside La Scala Opera House.</p>\r\n<p>After lunch, depart for Florence – the cradle of Renaissance art and culture.</p>\r\n<p>Visit Ponte Vecchio, a historic bridge spanning the Arno River, built in the 14th century.<br>\r\nExplore and shop at Mercato del Porcellino, one of the oldest markets in the world.</p>\r\n<p>Dinner and overnight in Florence.</p>'),(175,88,'vi','FLORENCE – PISA – ROME','Ăn sáng tại khách sạn, trả phòng.<p>Qúy khách lên xe và tham quan <strong>Tháp nghiêng Pisa</strong> - công trình kiến trúc độc đáo thu hút du khách đến tham quan chụp ảnh (chụp hình bên ngoài).</p><p>Đoàn ăn trưa tại nhà hàng địa phương\r\nSau đó đoàn khởi hành đến <strong>Rome </strong>cổ kính.</p><p>Tham quan <strong>Đấu trường La Mã Colosseum</strong> (chụp hình bên ngoài) - công trình lớn nhất được xây dựng dưới thời <strong>Đế chế La Mã</strong>.</p><p>Tham quan <strong>thác nước Trevi</strong> là đài phun nước hoành tráng nhất của thành Rome.</p><p>Đoàn ăn tối và về khách sạn check in.</p><p>Nghỉ đêm tại Rome.</p>'),(176,88,'en','FLORENCE – PISA – ROME','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Visit the Leaning Tower of Pisa – a unique architectural landmark (photo stop outside).</p>\r\n<p>After lunch, continue to Rome.<br>\r\nVisit the Colosseum (photo stop outside) – the largest structure built during the Roman Empire.<br>\r\nVisit the Trevi Fountain – the most magnificent fountain in Rome.</p>\r\n<p>Dinner and overnight in Rome.</p>'),(177,89,'vi','ROME CITY TOUR','Ăn sáng tại khách sạn.<p>Đoàn bắt đầu tham quan điểm tham quan đầu\r\ntiên là <strong>Vatican </strong>- một quốc gia độc lập ngay giữa thành <strong>Rome</strong>, với diện tích chưa đến 1km2 nhưng lại là một trong những quốc gia có quyền lực nhất thế giới.</p><p>Tham quan <strong>Thánh đường St. Peter</strong> - nơi thiêng liêng nhất ở <strong>Vatican</strong>, điểm thu hút tín đồ và du khách khắp thế giới.</p><p>Đoàn ăn trưa tại nhà hàng địa Phương\r\nBuổi chiều, Tham quan quảng trường <strong>Piazza Venezia</strong> - được dựng lên vào giữa thế kỷ 15 bởi <strong>Đức Hồng Y Pietro Barbo</strong>, người sau này trở thành giáo hoàng.</p><p>Sau khi tham quan quảng trường <strong>Piazza Venezia</strong>, Đoàn tự do shopping tại <strong>Designer Outlet Castel Romano</strong>, một trong những outlet lớn nhất ở Rome.</p><p>Đoàn ăn tối và về khách sạn nghỉ ngơi.\r\nNghỉ đêm tại Rome</p>'),(178,89,'en','ROME CITY TOUR','<p>Breakfast at the hotel.</p>\r\n<p>Visit Vatican City – an independent country located within Rome, one of the most powerful religious centers in the world.<br>\r\nExplore St. Peter’s Basilica – the most sacred site in Vatican City, attracting pilgrims and visitors worldwide.</p>\r\n<p>Lunch at a local restaurant.</p>\r\n<p>In the afternoon, visit Piazza Venezia, built in the 15th century by Cardinal Pietro Barbo (later Pope Paul II).</p>\r\n<p>Free time for shopping at Castel Romano Designer Outlet – one of the largest outlets in Rome.</p>\r\n<p>Dinner and overnight in Rome.</p>'),(179,90,'vi','ROME – HO CHI MINH CITY','Ăn sáng tại khách sạn.<p>Làm thủ tục trả phòng, Sau đó, xe đưa đoàn tham quan đền Patheon (chụp hình bên ngoài).<strong> Đền Pantheon</strong> là một trong những di tích La Mã cổ đại được bảo tồn tốt nhất hiện nay. Tên gọi \"Pantheon\" trong tiếng Latinh có nghĩa là \"Ngôi đền của mọi vị thần\". Kiến trúc mái vòm của đền được thiết kế để mô phỏng vòm trời, biểu trưng cho nơi ở của các thần linh.</p><p>Ăn trưa, ra sân bay đáp chuyến bay từ <strong>Rome </strong>về TP.HCM quá cảnh tùy hãng hàng không.</p>'),(180,90,'en','ROME – HO CHI MINH CITY','<p>Breakfast at the hotel and check-out.</p>\r\n<p>Visit the Pantheon (photo stop outside) – one of the best-preserved ancient Roman structures. The name “Pantheon” means “Temple of All Gods,” and its dome symbolizes the heavens.</p>\r\n<p>After lunch, transfer to the airport for the return flight to Ho Chi Minh City (transit depending on airline).</p>\r\n<p>Overnight on board.</p>'),(181,91,'vi','ĐẾN THÀNH PHỐ HỒ CHÍ MINH','Đến sân bay Tân Sơn Nhất, kết thúc chương trình tham quan.\r\nChia tay và hẹn gặp lại quý khách!'),(182,91,'en','ARRIVAL IN HO CHI MINH CITY','<p>Arrive at Tan Son Nhat International Airport. End of the tour program.</p>\r\n<p>Farewell and see you again on your next journey!</p>'),(223,112,'vi','ĐẾN SÀI GÒN','<p><strong>Sài Gòn</strong> (tên chính thức là Thành phố Hồ Chí Minh) là trung tâm thương mại, tài chính, văn hóa và du lịch của Việt Nam. Với hơn 300 năm lịch sử, Sài Gòn ngày nay là nơi giao thoa văn hóa và kết hợp giữa kiến trúc tân cổ điển với phong cách quốc tế. Thành phố từng được ca ngợi là “Hòn ngọc Viễn Đông”.</p><p>Sau khi hạ cánh, hướng dẫn viên sẽ đón quý khách tại sân bay và đưa đến nhà hàng để thưởng thức&nbsp;bữa tối chào mừng.</p><p>Sau đó, quý khách về khách sạn nhận phòng.</p><p>Nghỉ đêm tại Sài Gòn.</p>'),(224,112,'en','SAIGON ARRIVAL','<p><em>Saigon (official name known as Ho Chi Minh City) is the centre of commerce, finance, culture and tourism in Vietnam. With more than 300 years of history, nowadays Saigon is a location of cultural interaction as well as combination of neoclassical and international architecture. Saigon was then praised as ”Pearl of the &nbsp;Far East”. Fast-growing economy combining with city expansion allows retaining its traditional charm. Besides of this, Saigon is truly a hub, from which you can visit most of the attractive sites in the surroundings just within a day.</em></p><p>Upon arrival, our guide will greet you at the airport and transfer to restaurant for welcome dinner. Proceed to hotel for check-in.&nbsp;</p><p><em>Overnight in Saigon</em></p>'),(225,113,'vi','SÀI GÒN – ĐỒNG BẰNG SÔNG CỬU LONG – SÀI GÒN','<p>Khởi hành từ Sài Gòn đến <strong>Bến Tre</strong>, một phần của đồng bằng sông Cửu Long.</p><p>Đến <strong>Mỹ Tho</strong>, quý khách lên thuyền du ngoạn trên&nbsp;sông Tiền&nbsp;để sang Bến Tre. Trên đường đi, quý khách có cơ hội quan sát các bè cá nổi dọc cồn Rồng.</p><p>Tiếp tục qua <strong>rạch Xếp</strong> (Bến Tre) – vùng đất nổi tiếng với&nbsp;dừa&nbsp;– để tìm hiểu về quy trình thu hoạch dừa và cách người dân làm đồ thủ công từ thân và vỏ dừa. Sau đó, quý khách di chuyển bằng xe ngựa trên đường làng, ghé vườn ông Năm Ngô để thưởng thức&nbsp;mật ong pha trà hoặc rượu, tìm hiểu cách nuôi ong dưới tán cây nhãn và chụp ảnh cùng ong.</p><p>Quý khách sẽ tiếp tục&nbsp;chèo xuồng ba lá&nbsp;len lỏi giữa những rặng dừa nước trước khi dùng bữa trưa tại cồn.</p><p>Buổi chiều, quý khách tham quan xưởng sản xuất&nbsp;kẹo dừa&nbsp;và nếm thử đặc sản Bến Tre.</p><p>Trên đường về Sài Gòn, nếu còn thời gian, đoàn sẽ ghé thăm khu phố Hoa, chùa Thiên Hậu và xưởng sơn mài.</p><p>Nghỉ đêm tại Sài Gòn.</p>'),(226,113,'en','SAIGON – MEKONG DELTA – SAIGON','Depart Saigon for&nbsp;Ben Tre&nbsp;in Mekong Delta. Upon arrival in My Tho town, board a boat on&nbsp;Tien river&nbsp;to the other side (Ben Tre island). On the way, you have chance to observe floating fish farms along the Dragon islet. Then you are transferred through&nbsp;Xep canal&nbsp;in Ben Tre (known as “land of coconuts”) to see coconut collection set and how the local people make handicrafts from coconut trunk and shell. After that, you take the horse-cart on village paths and stop at Mr. Nam Ngo’s orchard to taste honey with tea or wine. Besides, you will learn about the bee-keeping in wooden boxes under longan trees and take photos with bees. You can also take rowing boat along palm creeks. After having lunch on the islet, boat to visit a coconut candy workshop and taste candy - special product of Ben Tre province.&nbsp; Transfer back to Saigon in the afternoon. On the way, stop to visit&nbsp;China town, Thien Hau pagoda&nbsp;and a lacquer shop if time permits.<p><em>Overnight in Saigon</em></p>'),(227,114,'vi','SÀI GÒN – ĐỊA ĐẠO CỦ CHI – SÀI GÒN – ĐÀ NẴNG – HỘI AN','<p>Sau khi trả phòng, quý khách khởi hành đi tham quan&nbsp;<strong>địa đạo Củ Chi</strong>, nằm cách Sài Gòn 75km về phía Tây Bắc. Hệ thống địa đạo dài 250km, bắt đầu được xây dựng vào những năm 1940 và mở rộng trong suốt 25 năm, đóng vai trò là nơi trú ẩn và sinh hoạt của quân dân Củ Chi trong thời kỳ chiến tranh.</p><p>Sau bữa trưa, quý khách ra sân bay để đáp chuyến bay đi <strong>Đà Nẵng</strong>.</p><p>Đến nơi, di chuyển đến <strong>Hội An</strong>, ăn tối tại nhà hàng địa phương, nhận phòng và&nbsp;nghỉ đêm tại Hội An.</p>'),(228,114,'en','SAIGON – CU CHI TUNNELS – SAIGON – DANANG – HOI AN','<p><em>Lying 75 km northwest of Saigon, Cu Chi tunnels, started to be constructed in 1940s and built over 25 years, stretch from the outskirts of Saigon to the Cambodian border with its length of 250 kilometers. During tens of years in the war, the tunnel system was considered the safe and solid shelter of Cu Chi army and people.</em></p><p>Check out and depart for Cu Chi, famous for an incredible underground tunnel network, constructed by Vietnamese resistance fighters during the long struggle for independence. The&nbsp;Cu Chi tunnel system&nbsp;had been created long time back, from 1948 to assist Vietnamese army in the combat with the French. This was regarded as an underground city with living areas, kitchens, storage, weapon factories, hospitals, command centers. The tunnel could house up to 10,000 people who virtually lived underground for years. After lunch, transfer to airport for the flight to Danang. Arrive in Danang, proceed to the riverside city of Hoi An, have dinner and then check in hotel.</p><p><em>Overnight in Hoi An</em></p>'),(229,115,'vi','HỘI AN','<p><strong>Hội An</strong> –&nbsp;Di sản Văn hóa Thế giới, là một trong những đô thị cổ được bảo tồn tốt nhất ở Đông Nam Á.</p><p>Buổi sáng, quý khách tham gia&nbsp;tour đi bộ&nbsp;khám phá phố cổ Hội An, tham quan các điểm nổi bật: <strong>Hội quán Phúc Kiến</strong>, <strong>chùa Cầu Nhật Bản</strong>, nhà cổ Tấn Ký, hội quán Triều Châu và mua sắm tại phố lụa.</p><p>Buổi chiều, quý khách tự do khám phá Hội An hoặc tham gia&nbsp;chuyến du thuyền trên <strong>sông Thu Bồn</strong>&nbsp;(khoảng 1 giờ) để ngắm hoàng hôn trước khi thưởng thức bữa tối.</p><p>Nghỉ đêm tại Hội An.</p>'),(230,115,'en','HOI AN','T<em>he classified Cultural Heritage of Hoi An Ancient Town is a marvel of centuries of preservation and propagation. Hoi An Ancient Town that measures a good 60 Sq Km in area is located in Hoi An city of Vietnam. Located on the banks of Thu Bon River, it was a place where several cultures merged to bring about the unique heritage that it has today.</em><p>Take a walking tour to&nbsp;Hoi An Ancient Quarters&nbsp;along small streets. Hoi An Ancient Town is an exceptionally well-preserved example of a South-East Asian trading port dating from 15th to 19th century. You will visit the&nbsp;Fukian Assembly Hall (Phuc Kien),&nbsp;Japanese Covered Bridge, Old House of Tan Ky, Chaozhou Hall (Trieu Chau)&nbsp;and go shopping at the silk streets.</p><p>In the afternoon, free at leisure for your own. Take a boat trip on&nbsp;Thu Bon river&nbsp;(about 1 hour) to admire the sunset of Hoi An before having dinner at local restaurant.</p><p><em>Overnight in Hoi An</em></p>'),(231,116,'vi','HỘI AN – ĐÀ NẴNG – HUẾ','<p>Sau bữa sáng, quý khách khởi hành đi Huế qua Đà Nẵng. Trên đường đi, ghé thăm<strong>&nbsp;Ngũ Hành Sơn</strong>&nbsp;(gồm 5 ngọn núi: Kim, Mộc, Thủy, Hỏa, Thổ) và&nbsp;<strong>Bảo tàng Điêu khắc Chăm</strong>, nơi lưu giữ bộ sưu tập điêu khắc Chăm lớn nhất thế giới.</p><p>Sau bữa trưa, tiếp tục hành trình qua&nbsp;đèo Hải Vân, dừng chân chụp ảnh tại&nbsp;<strong>bãi biển Lăng Cô</strong>&nbsp;– một trong những bãi biển đẹp nhất Việt Nam.</p><p>Đến Huế, nhận phòng khách sạn, ăn tối và&nbsp;nghỉ đêm tại Huế.</p>'),(232,116,'en','HOI AN – DA NANG – HUE','<p><em>Hue</em><em>&nbsp;city is one of particular sites in Vietnam which have many cultural heritages. Up to now, there has been no place preserving a lot of originally historical vestiges like this Ancient Capital City. Hue is also an important center of Buddhism. Hue and its surrounding still conserve tens of pagodas constructed more than 300 years ago, and a hundred of temples and pagodas built in the early centuries. Besides, this is the cradle of royal music, traditional famous dishes as well as sophisticated handicraft. And in December 1993, Hue was recognized as a World Cultural Heritage Site by UNESCO.</em></p><p>After breakfast, check out and transfer to Hue via Da Nang - a modern dynamic city in the Central. Stop to visit the&nbsp;Marble Mountains, also referred to as Ngu Hanh Son or Mountains of Five Elements, consisting of five marble mountains: Thuy Son (water) which is the highest, Moc Son (wood), Kim Son (metal), Tho Son (soil), and Hoa Son (fire) and&nbsp;Museum of Cham&nbsp;Sculpture built in 1915 with the most extensive collection of Cham art worldwide.</p><p>After lunch, continue the journey to Hue city. The scenic route passes&nbsp;Hai Van Pass&nbsp;(the Pass of Ocean Clouds) - one of the highest passes in Vietnam and dropping down to the wonderfully photogenic&nbsp;Lang Co Beach&nbsp;for sightseeing and taking photos.</p>'),(233,117,'vi','HUẾ','<p>Buổi sáng, quý khách lên thuyền dọc&nbsp;sông Hương&nbsp;để tham quan&nbsp;<strong>chùa Thiên Mụ</strong>&nbsp;– ngôi chùa hơn 400 năm tuổi. Tiếp tục tham quan&nbsp;Đại Nội, nơi các vua triều Nguyễn từng sinh sống và trị vì.</p><p>Buổi chiều, tham quan&nbsp;<strong>lăng Tự Đức</strong> và <strong>lăng Khải Định</strong>, nổi bật với kiến trúc độc đáo pha trộn giữa truyền thống Việt Nam và phong cách châu Âu.</p><p>Cuối ngày, dạo <strong>chợ Đông Ba</strong> mua sắm đặc sản Huế.</p><p>Nghỉ đêm tại Huế.</p>'),(234,117,'en','HUE','After breakfast, start to discover Hue - the former imperial capital of Vietnam. Take a morning boat trip on the romantically gentle&nbsp;Perfume River&nbsp;- one of the symbols of Ancient Hue Capital. Ending is at the seven-storey&nbsp;Thien Mu Pagoda, built in 1601 on the riverbank and then return to the car for a visit to the&nbsp;Imperial Citadel&nbsp;including Flag Tower, Ngo Mon Gate, Nine Dynastic Urns, Nine Holy Cannons, Thai Hoa Palace, Forbidden Purple City (Tu Cam Thanh) where all Kings in the Nguyen dynasty ruled from 1804 till 1945. Lunch at local restaurant. The afternoon tour will offer you some outstanding features in our history and architecture. Let’s take your trip to&nbsp;Mausoleum of Tu Duc King&nbsp;and&nbsp;Khai Dinh King! Architectural spotlights of Tu Duc Tomb include poetry elements in free form. Man-made elements were built and placed in strategic areas to achieve perfect harmony. Khai Dinh Tomb, 12th&nbsp;King of the Nguyen dynasty, shows the typical aspect of traditional Vietnamese design with a European touch making it unique from the other tombs in Hue. And its interior was wonderfully designed and decorated by colourful glass and pottery.<p>At last, stop at&nbsp;Dong Ba market&nbsp;to buy some Hue specialties then go to local restaurant for dinner.</p><p><em>Overnight in Hue</em></p><p></p>'),(235,118,'vi','HUẾ – HÀ NỘI','<p>Buổi sáng, ra sân bay đáp chuyến bay đi Hà Nội.</p><p>Sau khi đến Hà Nội, đoàn ghé thăm&nbsp;<strong>Bảo tàng Dân tộc học</strong>, tìm hiểu về 54 dân tộc của Việt Nam. Buổi chiều, tham quan&nbsp;<strong>Văn Miếu – Quốc Tử Giám</strong>, <strong>Hồ Hoàn Kiếm</strong> và tham gia&nbsp;tour xích lô&nbsp;khám phá khu phố cổ 36 phố phường.</p><p>Buổi tối, thưởng thức&nbsp;múa rối nước&nbsp;tại Nhà hát Thăng Long.</p><p>Nghỉ đêm tại Hà Nội.</p>'),(236,118,'en','HUE – HANOI','<p><em>Hanoi</em><em>&nbsp;is arguably the most charming capital in Asia. Hanoi, meaning ”where the river bends”, is a city of broad, tree-lined boulevards, elegant French villas and colonial-era buildings painted in muted hues of yellow and orange. It is also one of Asia’s greenest cities with an abundance of parks and lakes as well as a host of cafes and art galleries and an Old Quarter steeped in history.</em></p><p>After breakfast, transfer to airport for the flight to Hanoi. Upon arrival, our guide will greet you at airport and transfer to city center. On the way, stop to visit the&nbsp;Ethnology Museum&nbsp;where you are understood more about our rich culture of 54 different ethnic groups in Vietnam. Then head to hotel for check-in. After lunch at local restaurant, continue to visit Hanoi.</p><p>Proceed to&nbsp;Temple of Literature&nbsp;- Vietnam’s first university constructed in 1070. Its gardens and well-preserved architecture offer a relaxing glimpse into Vietnam’s past.&nbsp;Hoan Kiem Lake&nbsp;is also must-see sites for visitors to Hanoi.</p>'),(237,119,'vi','HÀ NỘI – HẠ LONG','<p>Sau bữa sáng, khởi hành đi&nbsp;<strong>Vịnh Hạ Long</strong>&nbsp;(170km). Đến nơi, quý khách lên&nbsp;<strong>du thuyền truyền thống</strong>, nhận phòng và thưởng thức bữa trưa trên tàu trong khi chiêm ngưỡng những hòn đảo đá vôi hùng vĩ.</p><p>Buổi chiều, tham quan&nbsp;<strong>làng chài Vung Viêng</strong>&nbsp;bằng thuyền nan, tìm hiểu cuộc sống của ngư dân và tham gia&nbsp;<strong>chèo kayak</strong>&nbsp;(tự túc).</p><p>Buổi tối, quý khách có thể tham gia lớp học nấu ăn hoặc thử câu mực đêm.</p><p>Nghỉ đêm trên tàu.</p>'),(238,119,'en','HANOI – HALONG','<p><em>Halong</em><em>&nbsp;Bay is perhaps the most spectacular of Vietnam\'s natural wonders. Located in the Gulf of Tonkin 170km from Hanoi, it is an impressive collection of nearly 2,000 islands covering an area in excess of 1,500km forming a magnificent seascape of limestone pillars and cliff faces. The breathtaking scenery and unusual geology of the bay led UNESCO to designate Halong Bay a World Heritage site in 1994, and it has been in the recommended list of World Natural Wonders.</em></p><p>After breakfast, leave Hanoi by road for&nbsp;Halong Bay. The journey sets along rich farmlands of the Red River Delta and the scenery of rice fields, water buffalo and&nbsp;daily Vietnamese village life. Arrive in Halong at noon and board a traditional junk&nbsp;for an amazing cruise on the emerald waters. After check in cabins, lunch is served while the cruise passes along beautiful islands. Take a rest for a moment, then transfer to rowing boats &amp; proceed to&nbsp;Vung Vieng&nbsp;fishing&nbsp;village&nbsp;to visit the floating village with the pearl farm. Let’s get chance to experience everyday activities of local people with the primary features in the charming nature! A rowing-boat competition (an exciting traditional activity) can be organized upon passengers’ request. After that, relax with kayaking (expense by yourselves) and swimming … in the clear water, beautiful and calm nature. Before enjoying scrumptious dinner, you can join cooking class with typical Vietnamese dishes. Night activities: relax on deck, beauty spa service, fishing, etc.</p><p><em>Overnight on board</em></p>'),(239,120,'vi','HẠ LONG – HÀ NỘI','<p>Dậy sớm ngắm bình minh trên vịnh, tham gia&nbsp;<strong>lớp học Thái Cực Quyền</strong>&nbsp;trên boong tàu.</p><p>Sau bữa sáng nhẹ, tham quan&nbsp;<strong>hang Sửng Sốt</strong>, một trong những hang động đẹp nhất Hạ Long.</p><p>Sau đó, dùng bữa trưa buffet trước khi trở lại bến cảng và di chuyển về Hà Nội.</p><p>Nghỉ đêm tại Hà Nội.</p>'),(240,120,'en','HALONG – HANOI','Get up early to watch the sunrise over the bay and take part in our morning Tai Chi class on sundeck. Then have light breakfast with bread, milk, coffee, tea. After that, you will explore&nbsp;Sung Sot (“Surprise”) Cave&nbsp;- the largest cave in Halong bay. Return to the junk, check out cabins and have international buffet brunch. Arrive at&nbsp;Hon Gai&nbsp;pier and transfer back to Hanoi. Have dinner at local restaurant.<p><em>Overnight in Hanoi</em></p>'),(241,121,'vi','HÀ NỘI – TIỄN SÂN BAY','Sau bữa sáng, quý khách tự do đến giờ ra sân bay cho chuyến bay tiếp theo.'),(242,121,'en','HANOI OUT','Breakfast at hotel. Free at leisure until time to transfer to airport for the onward flight.'),(243,122,'vi','VIỆT NAM – THƯỢNG HẢI','<p>04:00 Hướng dẫn viên Travel Plus đón Quý khách tại sân bay TSN, làm<br>thủ tục bay trên chuyến bay đi Thương Hải.<br>Đến nơi, Sau khi làm thủ tục nhập cảnh, Quý khách gặp hướng dẫn viên địa<br>phương và di chuyển đến nhà hàng địa phương để ăn tối – Quý khách làm<br>thủ tục nhận phòng khách sạn.<br>Quý khách tham quan:<br>- Bến Thượng Hải– biểu tượng lịch sử và hiện đại của Thượng Hải,<br>là một trong những điểm đến không thể bỏ qua. Tản bộ trên bến<br>thượng hải có thể tậng hưởng những cảnh đẹp và kiến trúc nổi bật<br>dãy công trình mang phong cách Châu Âu cổ kính, tạo nên khung<br>cảnh lãng mạn và hoài niệm.<br>- Chiêm ngưỡng biểu tượng của Thượng Hải – cầu Nam Phố - con<br>rồng uống lượn qua dòng sông Hoàng Phố tráng lệ.<br>- Tháp truyền hình Minh Châu Phương Đông – một trong ba tháp<br>truyền hình cao nhất thế giới (chụp hình bên ngoài). Quy khách tự<br>do tham quan và mua sắm trên đại lộ Nam Kinh, được mệnh là<br>“Trung Hoa đệ nhất lộ”.<br>Quý khách sẽ ăn tối tại nhà hàng địa phương, khách lên xe nhận phòng<br>khách sạn.<br>Nghỉ đêm tại Thượng Hải.<br></p>'),(244,122,'en','VIỆT NAM – THƯỢNG HẢI','<p>04:00 Hướng dẫn viên Travel Plus đón Quý khách tại sân bay TSN, làm<br>thủ tục bay trên chuyến bay đi Thương Hải.<br>Đến nơi, Sau khi làm thủ tục nhập cảnh, Quý khách gặp hướng dẫn viên địa<br>phương và di chuyển đến nhà hàng địa phương để ăn tối – Quý khách làm<br>thủ tục nhận phòng khách sạn.<br>Quý khách tham quan:<br>- Bến Thượng Hải– biểu tượng lịch sử và hiện đại của Thượng Hải,<br>là một trong những điểm đến không thể bỏ qua. Tản bộ trên bến<br>thượng hải có thể tậng hưởng những cảnh đẹp và kiến trúc nổi bật<br>dãy công trình mang phong cách Châu Âu cổ kính, tạo nên khung<br>cảnh lãng mạn và hoài niệm.<br>- Chiêm ngưỡng biểu tượng của Thượng Hải – cầu Nam Phố - con<br>rồng uống lượn qua dòng sông Hoàng Phố tráng lệ.<br>- Tháp truyền hình Minh Châu Phương Đông – một trong ba tháp<br>truyền hình cao nhất thế giới (chụp hình bên ngoài). Quy khách tự<br>do tham quan và mua sắm trên đại lộ Nam Kinh, được mệnh là<br>“Trung Hoa đệ nhất lộ”.<br>Quý khách sẽ ăn tối tại nhà hàng địa phương, khách lên xe nhận phòng<br>khách sạn.<br>Nghỉ đêm tại Thượng Hải.<br></p>'),(245,123,'vi','THƯỢNG HẢI – HÀNG CHÂU (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn và tiếp tục hành trình.&nbsp;<p><br></p><p>Tham quan\r\n<strong>Chùa Phật Ngọc</strong> – ngôi chùa linh thiêng và nổi tiếng nhất Thượng Hải.</p><p><br></p><p>Tiếp\r\ntục hành trình đến với Phố cổ Dự Viên – một trong địa điểm không thể bỏ\r\nlỡ khi đến Thương Hải, nỗi bật nhất là khu vườn Dự Viên, khu vườn cổ tuyệt\r\nđẹp được xây dựng từ thời Minh với kiến trúc truyền thông tinh tế. hồ cá\r\nKoi, cầu đá uốn lượn và những ngôi nhà gỗ cỗ kính.</p><p><br></p><p>Quý khách tham quan Miến Thành Hoàng – khu phố cổ mang đậm kiến trúc\r\ntruyền thống và nhịp sống nhộn nhịp.\r\nThưởng thức trà Long Tĩnh - là nơi sản xuất loại trà xanh danh tiếng bậc\r\nnhất Trung Quốc.</p><p><br></p><p>Đến đây, du khách có cơ hội tận tay hái những búp trà non\r\nvà thưởng thức nghệ thuật pha trà và thưởng thức trà Long Tỉnh thơm dịu,\r\nthanh mát.\r\nKhởi hành đến Hàng Châu.</p><p><br></p><p>Quý khách ăn tối tại nhà hàng địa phương và lên xe\r\nnhận phòng khách sạn.</p><p><br></p><p>Nghỉ đêm tại Hàng Châu.&nbsp;</p>'),(246,123,'en','THƯỢNG HẢI – HÀNG CHÂU (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn và tiếp tục hành trình.&nbsp;<p><br></p><p>Tham quan\r\n<strong>Chùa Phật Ngọc</strong> – ngôi chùa linh thiêng và nổi tiếng nhất Thượng Hải.</p><p><br></p><p>Tiếp\r\ntục hành trình đến với Phố cổ Dự Viên – một trong địa điểm không thể bỏ\r\nlỡ khi đến Thương Hải, nỗi bật nhất là khu vườn Dự Viên, khu vườn cổ tuyệt\r\nđẹp được xây dựng từ thời Minh với kiến trúc truyền thông tinh tế. hồ cá\r\nKoi, cầu đá uốn lượn và những ngôi nhà gỗ cỗ kính.</p><p><br></p><p>Quý khách tham quan Miến Thành Hoàng – khu phố cổ mang đậm kiến trúc\r\ntruyền thống và nhịp sống nhộn nhịp.\r\nThưởng thức trà Long Tĩnh - là nơi sản xuất loại trà xanh danh tiếng bậc\r\nnhất Trung Quốc.</p><p><br></p><p>Đến đây, du khách có cơ hội tận tay hái những búp trà non\r\nvà thưởng thức nghệ thuật pha trà và thưởng thức trà Long Tỉnh thơm dịu,\r\nthanh mát.\r\nKhởi hành đến Hàng Châu.</p><p><br></p><p>Quý khách ăn tối tại nhà hàng địa phương và lên xe\r\nnhận phòng khách sạn.</p><p><br></p><p>Nghỉ đêm tại Hàng Châu.&nbsp;</p>'),(247,124,'vi','HÀNG CHÂU – TÔ CHÂU (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn, sau đó quý khách sẽ khám phá vẻ\r\nđẹp nên thơ đặc trưng của vùng Giang Nam.<p><br></p><p>Tây Hồ- với vẻ đẹp được cô đọng qua Tây Hồ thập cảnh (mười cảnh đẹp\r\ncủa Tây Hồ). Mỗi phong cảnh này đều được đánh dấu bằng một cái bia với\r\ntên gọi được chính hoàng đế Càn Long nhà Thanh viết theo kiểu thư pháp.</p><p>Chiêm ngưỡng Tam Đàn Ấn Nguyệt, biểu tượng mang đậm chất thơ của\r\nTây Hồ.</p><p>Viếng miếu Nhạc Phi, đấu ấn lịch sử về vị tướng trung nghĩ thời Nam Tống.</p><p>Nghỉ đêm tại Tô Châu</p>'),(248,124,'en','HÀNG CHÂU – TÔ CHÂU (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn, sau đó quý khách sẽ khám phá vẻ\r\nđẹp nên thơ đặc trưng của vùng Giang Nam.<p><br></p><p>Tây Hồ- với vẻ đẹp được cô đọng qua Tây Hồ thập cảnh (mười cảnh đẹp\r\ncủa Tây Hồ). Mỗi phong cảnh này đều được đánh dấu bằng một cái bia với\r\ntên gọi được chính hoàng đế Càn Long nhà Thanh viết theo kiểu thư pháp.</p><p>Chiêm ngưỡng Tam Đàn Ấn Nguyệt, biểu tượng mang đậm chất thơ của\r\nTây Hồ.</p><p>Viếng miếu Nhạc Phi, đấu ấn lịch sử về vị tướng trung nghĩ thời Nam Tống.</p><p>Nghỉ đêm tại Tô Châu</p>'),(249,125,'vi','TÔ CHÂU – BẮC KINH (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn.<p>Đoàn khám phá chiều sâu văn hóa\r\nvà nghệ thuật kiến trúc cổ truyền Trung Hoa.</p><p>- Tham quan Hàn Sơn Tự, không gian cổ kính với tiếng chuông chùa\r\nvang vọng đặc trưng.</p><p>- Chiêm ngưỡng Sư Tử Lâm, nghệ thuật vườn đá độc đáo tạo thành\r\nmê cung sinh động.</p><p>- Ghé tham quan xưởng sản xuất tơ lụa nổi tiếng.\r\nQuý khách di chuyển bằng tàu cao tốc đến Bắc Kinh.</p><p>Ăn tối tại khách sạn địa phương và lên xe nhận phòng khách sạn.</p><p>&nbsp;Nghỉ đêm tại Bắc Kinh.</p>'),(250,125,'en','TÔ CHÂU – BẮC KINH (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm tại khách sạn.<p>Đoàn khám phá chiều sâu văn hóa\r\nvà nghệ thuật kiến trúc cổ truyền Trung Hoa.</p><p>- Tham quan Hàn Sơn Tự, không gian cổ kính với tiếng chuông chùa\r\nvang vọng đặc trưng.</p><p>- Chiêm ngưỡng Sư Tử Lâm, nghệ thuật vườn đá độc đáo tạo thành\r\nmê cung sinh động.</p><p>- Ghé tham quan xưởng sản xuất tơ lụa nổi tiếng.\r\nQuý khách di chuyển bằng tàu cao tốc đến Bắc Kinh.</p><p>Ăn tối tại khách sạn địa phương và lên xe nhận phòng khách sạn.</p><p>&nbsp;Nghỉ đêm tại Bắc Kinh.</p>'),(251,126,'vi','BẮC KINH (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm sáng tại khách sạn sau đó xe đưa đoàn đến\r\nVạn Lý Trường Thành một trong những kỳ quan hùng vĩ nhất của thế giới\r\nvà là niềm tự hào của người Trung Quốc với câu thơ bất hủ “Bất Đáo\r\nTrường Thành phi Hảo Hán”. Được xây dựng bằng đá và đất từ thế kỉ 5 TCN\r\nđến thế kỉ 16, với mục đich phòng thủ chống lại các xâm lược của các bộ tộc\r\ndu mục từ phía Bắc.<p>Tham quan Cư Dung Quan, cửa ải kiên cố với kiến trúc đồ sộ và vị trí chiến\r\nlược quan trọng.</p><p>Ghé thăm Định Lăng, khám phá không gian lăng mộ cổ với nhiều bí ẩn của\r\ntriều địa Nhà Minh.</p><p>Chụp hình bên ngoài Sân vận động Tổ chim, biểu tượng kiến trúc hiện đại\r\ncủa Bắc Kinh</p><p>&nbsp;Đoàn ăn tối tại nhà hàng địa phương và lên xe về khách sạn nghỉ ngơi.</p><p>Nghỉ đêm tại Bắc Kinh.&nbsp;</p>'),(252,126,'en','BẮC KINH (ĂN SÁNG, TRƯA, TỐI)','Quý khách dùng điểm tâm sáng tại khách sạn sau đó xe đưa đoàn đến\r\nVạn Lý Trường Thành một trong những kỳ quan hùng vĩ nhất của thế giới\r\nvà là niềm tự hào của người Trung Quốc với câu thơ bất hủ “Bất Đáo\r\nTrường Thành phi Hảo Hán”. Được xây dựng bằng đá và đất từ thế kỉ 5 TCN\r\nđến thế kỉ 16, với mục đich phòng thủ chống lại các xâm lược của các bộ tộc\r\ndu mục từ phía Bắc.<p>Tham quan Cư Dung Quan, cửa ải kiên cố với kiến trúc đồ sộ và vị trí chiến\r\nlược quan trọng.</p><p>Ghé thăm Định Lăng, khám phá không gian lăng mộ cổ với nhiều bí ẩn của\r\ntriều địa Nhà Minh.</p><p>Chụp hình bên ngoài Sân vận động Tổ chim, biểu tượng kiến trúc hiện đại\r\ncủa Bắc Kinh</p><p>&nbsp;Đoàn ăn tối tại nhà hàng địa phương và lên xe về khách sạn nghỉ ngơi.</p><p>Nghỉ đêm tại Bắc Kinh.&nbsp;</p>'),(253,127,'vi','BẮC KINH (ĂN SÁNG, ĂN TRƯA, ĂN TỐI)','Quý khách ăn sáng tại khách sạn sau đó xe đưa đoàn tham quan:<p>- Dạo chơi Quảng tường Thiên An Môn, không gian rộng lớn mang ý\r\nnghĩa lịch sử quan trọng.</p><p>- Tham quan Tử Cấm Thành, quần thể cung điện nguy nga phản ánh\r\nquyền lực và cuộc sống hoàng gia xưa.</p><p>- Tham quan Di Hòa Viên, khu vườn hoàng gia tuyệ mỹ với hồ nước\r\nvà hành lang dài nổi tiếng.</p><p>- Muc sắm tại cửa hàng cao su và Đồng Nhân Đường.</p><p>Đoàn ăn tối tại nhà hàng địa phương và lên xe về khách sạn nghỉ ngơi.</p><p>Nghỉ đêm tại Bắc Kinh.</p>'),(254,127,'en','BẮC KINH (ĂN SÁNG, ĂN TRƯA, ĂN TỐI)','Quý khách ăn sáng tại khách sạn sau đó xe đưa đoàn tham quan:<p>- Dạo chơi Quảng tường Thiên An Môn, không gian rộng lớn mang ý\r\nnghĩa lịch sử quan trọng.</p><p>- Tham quan Tử Cấm Thành, quần thể cung điện nguy nga phản ánh\r\nquyền lực và cuộc sống hoàng gia xưa.</p><p>- Tham quan Di Hòa Viên, khu vườn hoàng gia tuyệ mỹ với hồ nước\r\nvà hành lang dài nổi tiếng.</p><p>- Muc sắm tại cửa hàng cao su và Đồng Nhân Đường.</p><p>Đoàn ăn tối tại nhà hàng địa phương và lên xe về khách sạn nghỉ ngơi.</p><p>Nghỉ đêm tại Bắc Kinh.</p>'),(255,128,'vi','BẮC KINH – VIỆT NAM (ĂN SÁNG, ĂN TRƯA)','Qúy khách làm thủ tục trả phòng tự do mua sắm.<p>Sau khi ăn trưa xe đưa Quý\r\nkhách ra sân bay Bắc Kinh làm thủ tục xuất cảnh đáp chuyến bay về HCM.</p><p>Đến sân bay Tân Sơn Nhất.\r\nKết thúc chương trình du lịch Trung quốc cùng cty du lịch Travel Plus.</p>'),(256,128,'en','BẮC KINH – VIỆT NAM (ĂN SÁNG, ĂN TRƯA)','Qúy khách làm thủ tục trả phòng tự do mua sắm.<p>Sau khi ăn trưa xe đưa Quý\r\nkhách ra sân bay Bắc Kinh làm thủ tục xuất cảnh đáp chuyến bay về HCM.</p><p>Đến sân bay Tân Sơn Nhất.\r\nKết thúc chương trình du lịch Trung quốc cùng cty du lịch Travel Plus.</p>');
