CREATE TABLE `tour_reviews` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tour_id` int NOT NULL,
  `reviewer_name` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `reviewer_email` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `rating_overall` decimal(3,2) DEFAULT NULL,
  `rating_destination` decimal(3,2) DEFAULT NULL,
  `rating_transport` decimal(3,2) DEFAULT NULL,
  `rating_value` decimal(3,2) DEFAULT NULL,
  `title` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `content` longtext COLLATE utf8mb4_general_ci,
  `status` enum('pending','approved','hidden') COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'pending',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tour_reviews_tour_id` (`tour_id`),
  CONSTRAINT `fk_tour_reviews_tour_id` FOREIGN KEY (`tour_id`) REFERENCES `tours` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
