CREATE TABLE `tour_translations` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tour_id` int NOT NULL,
  `locale` varchar(10) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `short_description` text COLLATE utf8mb4_unicode_520_ci,
  `overview` longtext COLLATE utf8mb4_unicode_520_ci,
  `description` longtext COLLATE utf8mb4_unicode_520_ci,
  `itinerary` longtext COLLATE utf8mb4_unicode_520_ci,
  `booking_policy` longtext COLLATE utf8mb4_unicode_520_ci,
  `cancellation_policy` longtext COLLATE utf8mb4_unicode_520_ci,
  `price_note` text COLLATE utf8mb4_unicode_520_ci,
  `meta_title` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `meta_description` text COLLATE utf8mb4_unicode_520_ci,
  PRIMARY KEY (`id`),
  UNIQUE KEY `tour_id` (`tour_id`,`locale`),
  CONSTRAINT `tour_translations_ibfk_1` FOREIGN KEY (`tour_id`) REFERENCES `tours` (`id`) ON DELETE CASCADE
