INSERT INTO `tour_translations` VALUES (11,6,'vi','THAM QUAN DU LỊCH MỸ: HAI BỜ ĐÔNG TÂY (13N12Đ)','tham-quan-du-lich-my-hai-bo-dong-tay-13n1d2','Hoa Kỳ (Mỹ) miền đất hứa ngày nay vẫn là điểm hẹn du lịch mơ ước.','','Tour du lịch nước Mỹ từ Bờ Đông sang Bờ Tây, được coi là chuyến đi thế giới thu nhỏ, vô số kỳ quan thiên nhiên, thành phố lịch sử và khu giải trí.','','','','','THAM QUAN DU LỊCH MỸ: HAI BỜ ĐÔNG TÂY (13N12Đ)','Tour du lịch nước Mỹ từ Bờ Đông sang Bờ Tây, được coi là chuyến đi thế giới thu nhỏ, vô số kỳ quan thiên nhiên, thành phố lịch sử và khu giải trí.'),(12,6,'en','USA TOUR: DISCOVERING BOTH EAST & WEST COASTS (13D12N)','usa-tour-discovering-both-east-west-coats-13n12d','The United States of America remains one of the world’s most dream-worthy travel destinations.','','Journey across the East and West Coasts of the USA — a fascinating adventure often described as a miniature world of its own, filled with breathtaking natural wonders, iconic historical cities, and vibrant entertainment hubs.','','','','','USA TOUR: DISCOVERING BOTH EAST & WEST COASTS (13D12N)','Journey across the East and West Coasts of the USA — a fascinating adventure often described as a miniature world of its own, filled with breathtaking natural wonders, iconic historical cities, and vibrant entertainment hubs.'),(17,4,'vi','Hà Nội - Đà Nẵng 4N3Đ','ha-noi-da-nang-4n3d','Biển Mỹ Khê và Bà Nà Hills','','','','','','','',''),(18,4,'en','Hanoi - Danang 4 Days','hanoi-danang-4-days','Danang beach holiday','','','','','','','',''),(19,3,'vi','Hà Nội - Sa Pa 3N2Đ','ha-noi-sapa-3n2d','Trekking và săn mây Sa Pa','','','','','','','',''),(20,3,'en','Hanoi - Sapa 3 Days','hanoi-sapa-3-days','Sapa trekking experience','','','','','','','',''),(21,2,'vi','Hà Nội - Paris 7N6Đ','ha-noi-paris-7n6d','Tham quan tháp Eiffel và châu Âu lãng mạn','','','','','','','',''),(22,2,'en','Hanoi - Paris 7 Days','hanoi-paris-7-days','Romantic Europe journey','','','','','','','',''),(23,1,'vi','Hà Nội - Tokyo 5N4Đ','ha-noi-tokyo-5n4d','Khám phá Tokyo mùa hoa anh đào','','','','','','','',''),(24,1,'en','Hanoi - Tokyo 5 Days','hanoi-tokyo-5-days','Discover Tokyo in cherry blossom season','','','','','','','',''),(33,5,'vi','KHÁM PHÁ TÂY ÂU: PHÁP – THỤY SĨ – Ý (10N9Đ)','kham-pha-tay-au-phap-thuy-si-y-10n9d','Tour du lịch châu Âu đến Pháp - Thụy Sỹ - Ý là hành trình trải nghiệm đầy lý thú. Du khách sẽ được khám phá xuyên suốt các thành phố danh tiếng như Paris, Milan, Venice, Pisa, Florence, Rome, Zurich…; đặt chân đến sông Seine thơ mộng, tháp nghiêng Pisa, thành Rome hùng tráng, tòa thánh Vatican linh thiêng, núi Titlis phủ tuyết trắng quanh năm… và tận mắt chiêm ngưỡng vô vàn các công trình kiến trúc danh tiếng, các thắng cảnh nên thơ, các chứng tích lịch sử cổ kính.','','Tour du lịch châu Âu đến Pháp - Thụy Sỹ - Ý là hành trình trải nghiệm đầy lý thú. Du khách sẽ được khám phá xuyên suốt các thành phố danh tiếng như Paris, Milan, Venice, Pisa, Florence, Rome, Zurich…; đặt chân đến sông Seine thơ mộng, tháp nghiêng Pisa, thành Rome hùng tráng, tòa thánh Vatican linh thiêng, núi Titlis phủ tuyết trắng quanh năm… và tận mắt chiêm ngưỡng vô vàn các công trình kiến trúc danh tiếng, các thắng cảnh nên thơ, các chứng tích lịch sử cổ kính.','','','','','Tour Châu Âu Pháp – Thụy Sĩ – Ý 10N9Đ | Paris – Rome – Milan – Zurich','Khám phá tour châu Âu 10N9Đ qua Pháp – Thụy Sĩ – Ý: Paris lãng mạn, núi Titlis tuyết phủ, Venice, Rome cổ kính. Lịch trình hấp dẫn, trọn gói, trải nghiệm đẳng cấp.'),(34,5,'en','WESTERN EUROPE DISCOVERY: FRANCE – SWITZERLAND – ITALY (10 DAYS 9 NIGHTS)','western-europe-discovery-france-switzerland-italy-10d9n','The Europe tour to France – Switzerland – Italy is a truly captivating journey of discovery. Travelers will explore a series of iconic cities such as Paris, Milan, Venice, Pisa, Florence, Rome, and Zurich; set foot along the romantic Seine River, marvel at the Leaning Tower of Pisa, admire the grandeur of Rome, experience the sacred atmosphere of Vatican City, and witness the year-round snow-covered peaks of Mount Titlis… Along the way, they will be immersed in a world of renowned architectural masterpieces, poetic landscapes, and timeless historical landmarks.','','The Europe tour to France – Switzerland – Italy is a truly captivating journey of discovery. Travelers will explore a series of iconic cities such as Paris, Milan, Venice, Pisa, Florence, Rome, and Zurich; set foot along the romantic Seine River, marvel at the Leaning Tower of Pisa, admire the grandeur of Rome, experience the sacred atmosphere of Vatican City, and witness the year-round snow-covered peaks of Mount Titlis… Along the way, they will be immersed in a world of renowned architectural masterpieces, poetic landscapes, and timeless historical landmarks.','','','','','Europe Tour France – Switzerland – Italy 10 Days | Paris, Rome, Milan, Zurich','Discover a 10-day Europe tour through France, Switzerland, and Italy: romantic Paris, snowy Mount Titlis, Venice canals, and historic Rome. All-inclusive itinerary with premium experiences.'),(39,7,'vi','Tinh Hoa Việt Nam – Hành Trình Di Sản (10N9Đ)','tinh-hoa-viet-nam-10n9d','Hành trình xuyên Việt 10 ngày 9 đêm đưa du khách khám phá vẻ đẹp tinh hoa của Việt Nam qua những điểm đến nổi bật từ Bắc vào Nam, kết hợp giữa thiên nhiên, văn hóa, di sản và ẩm thực đặc sắc.','','“Tinh Hoa Việt Nam” là hành trình đặc biệt dành cho du khách muốn cảm nhận trọn vẹn vẻ đẹp đất nước hình chữ S qua những danh lam thắng cảnh, di sản văn hóa và nét đẹp truyền thống đặc trưng của từng vùng miền.','','','','','TINH HOA VIỆT NAM (10N9Đ)','Hành trình xuyên Việt 10 ngày 9 đêm đưa du khách khám phá vẻ đẹp tinh hoa của Việt Nam qua những điểm đến nổi bật từ Bắc vào Nam, kết hợp giữa thiên nhiên, văn hóa, di sản và ẩm thực đặc sắc.'),(40,7,'en','Vietnam Essence – Heritage Journey (10D9N)','essence-of-vietnam-10d9n','A 10-day, 9-night journey across Vietnam, exploring the country’s finest destinations from North to South, featuring breathtaking landscapes, rich cultural heritage, and authentic local experiences.','','“Essence of Vietnam” is a specially curated journey designed for travelers who wish to discover the beauty, culture, and spirit of Vietnam through its most iconic destinations.','','','','','ESSENCE OF VIETNAM (10D9N)','“Essence of Vietnam” is a specially curated journey designed for travelers who wish to discover the beauty, culture, and spirit of Vietnam through its most iconic destinations.'),(41,8,'vi','Khám Phá Tinh Hoa Trung Hoa: Thượng Hải – Ô Trấn – Bắc Kinh (7N6Đ)','kham-pha-tinh-hoa-trung-hoa-thuong-hai-o-tran-bac-kinh-7n6','Hành trình đưa bạn qua những điểm đến nổi bật nhất Trung Quốc','','Hành trình đưa bạn qua những điểm đến nổi bật nhất Trung Quốc: Thượng Hải hiện đại, Hàng Châu thơ mộng, Ô Trấn cổ kính và Bắc Kinh hùng vĩ. Trải nghiệm trọn vẹn vẻ đẹp văn hóa, lịch sử và nhịp sống đặc sắc của xứ Trung Hoa.','','','','','Khám Phá Tinh Hoa Trung Hoa: Thượng Hải – Ô Trấn – Bắc Kinh (7N6Đ)','Hành trình đưa bạn qua những điểm đến nổi bật nhất Trung Quốc: Thượng Hải hiện đại, Hàng Châu thơ mộng, Ô Trấn cổ kính và Bắc Kinh hùng vĩ. Trải nghiệm trọn vẹn vẻ đẹp văn hóa, lịch sử và nhịp sống đặc sắc của xứ Trung Hoa.'),(42,8,'en','Khám Phá Tinh Hoa Trung Hoa: Thượng Hải – Ô Trấn – Bắc Kinh (7N6Đ)','kh-am-ph-a-tinh-hoa-trung-hoa-thng-hi-o-trn-bc-kinh-7n6d','','','','','','','','','');
/*!40000 ALTER TABLE `tour_translations` ENABLE KEYS */;
