DROP TABLE IF EXISTS `tours`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tours` (
  `id` int NOT NULL AUTO_INCREMENT,
  `sku` varchar(100) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `code` varchar(100) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `category_id` int NOT NULL,
  `departure_location_id` int NOT NULL,
  `primary_destination_id` int DEFAULT NULL,
  `tour_type` enum('inbound','outbound') COLLATE utf8mb4_unicode_520_ci NOT NULL,
  `duration_days` int NOT NULL,
  `duration_nights` int NOT NULL,
  `min_travelers` int DEFAULT NULL,
  `max_travelers` int DEFAULT NULL,
  `base_price` int DEFAULT NULL,
  `sale_price` int DEFAULT NULL,
  `child_price_rate` decimal(5,4) NOT NULL DEFAULT '0.8500',
  `infant_price_rate` decimal(5,4) NOT NULL DEFAULT '0.2500',
  `currency` varchar(10) COLLATE utf8mb4_unicode_520_ci NOT NULL DEFAULT 'VND',
  `rating_avg` decimal(3,2) DEFAULT NULL,
  `reviews_count` int NOT NULL DEFAULT '0',
  `thumbnail` varchar(255) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `map_embed` text COLLATE utf8mb4_unicode_520_ci,
  `is_featured` tinyint(1) DEFAULT '0',
  `is_promotion` tinyint(1) NOT NULL DEFAULT '0',
  `promotion_badge` varchar(80) COLLATE utf8mb4_unicode_520_ci DEFAULT NULL,
  `promotion_ends_at` datetime DEFAULT NULL,
  `promotion_sort` int NOT NULL DEFAULT '0',
  `view_count` int unsigned NOT NULL DEFAULT '0',
  `status` enum('draft','published') COLLATE utf8mb4_unicode_520_ci DEFAULT 'draft',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `category_id` (`category_id`),
  KEY `departure_location_id` (`departure_location_id`),
  KEY `idx_tours_home_promotion` (`is_promotion`,`promotion_sort`,`promotion_ends_at`),
  CONSTRAINT `tours_ibfk_1` FOREIGN KEY (`category_id`) REFERENCES `tour_categories` (`id`),
  CONSTRAINT `tours_ibfk_2` FOREIGN KEY (`departure_location_id`) REFERENCES `locations` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_520_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

